/**
 * Writes api/org_icon_whitelist.json + lib/orgLucideIconNames.gen.ts from lucide-react's iconNames.
 * Run: npm run gen:org-icons
 */
import { writeFileSync } from 'fs';
import { dirname, join } from 'path';
import { fileURLToPath } from 'url';
import { iconNames } from 'lucide-react/dynamic.mjs';

const __dirname = dirname(fileURLToPath(import.meta.url));
const root = join(__dirname, '..');
const sorted = [...iconNames].sort((a, b) => a.localeCompare(b));

writeFileSync(join(root, 'api', 'org_icon_whitelist.json'), JSON.stringify(sorted));

const ts =
  '/** Auto-generated by `npm run gen:org-icons` — do not edit. */\n' +
  `export const ORG_LUCIDE_ICON_NAMES = ${JSON.stringify(sorted)} as readonly string[];\n`;
writeFileSync(join(root, 'lib', 'orgLucideIconNames.gen.ts'), ts);

console.log(`Wrote ${sorted.length} icon names to api/org_icon_whitelist.json and lib/orgLucideIconNames.gen.ts`);
